    const isAllOpen = openIndexes.length === itineraryData.length;

    const toggleAll = () => {
        if (isAllOpen) {
            setOpenIndexes([]);
        } else {
            setOpenIndexes(itineraryData.map((_, i) => i));
        }
    };

    const [openItems, setOpenItems] = useState<number[]>([0]);
